@namespace Lumeo

@*
    FeatureGrid — responsive 1/2/3-column grid for landing-page feature
    callouts. Part of the 3.4 Splash Kit. Pair with <FeatureItem> children
    or pass raw ChildContent for full control.
*@

<section class="@CssClass" @attributes="AdditionalAttributes">
    <div class="mx-auto max-w-6xl px-6 py-16">
        @if (!string.IsNullOrEmpty(Title))
        {
            <h2 class="text-3xl font-bold tracking-tight text-foreground text-center">@Title</h2>
        }
        @if (!string.IsNullOrEmpty(Subtitle))
        {
            <p class="mt-3 text-muted-foreground text-center max-w-2xl mx-auto">@Subtitle</p>
        }
        <div class="@($"mt-12 grid gap-8 {ColumnsClass}")">
            @ChildContent
        </div>
    </div>
</section>

@code {
    [Parameter] public string? Title { get; set; }
    [Parameter] public string? Subtitle { get; set; }
    [Parameter] public int Columns { get; set; } = 3;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("w-full", Class);

    private string ColumnsClass => Columns switch
    {
        1 => "grid-cols-1",
        2 => "grid-cols-1 sm:grid-cols-2",
        4 => "grid-cols-1 sm:grid-cols-2 lg:grid-cols-4",
        _ => "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3"
    };
}
